document.addEventListener("DOMContentLoaded", () => {
    const widthScreen = window.innerWidth || document.documentElement.clientWidth ||
        document.body.clientWidth;

    Fancybox.bind("[data-fancybox]", {
        placeFocusBack: false
    });

    if (document.getElementById('homeSlider')) {
        const progressPage = document.getElementById("homeSlider");
        new Swiper('#homeSlider', {
            lazyPreloadPrevNext: 1,
            spaceBetween: 26,
            slidesPerView: 1,
            loop: true,
            autoplay: {
                delay: 2000,
                disableOnInteraction: false,
            },
            parallax: true,
            speed: 1000,
            pagination: {
                el: '.home-slider__paginate',
                clickable: true,
            },
            on: {
                autoplayTimeLeft(s, time, progress) {
                    progressPage.style.setProperty("--progress", ((1 - progress) * 100) + '%');
                }
            }
        });
    }

    if (document.getElementById('brandSlider')) {

        new Swiper('#brandSlider', {
            lazyPreloadPrevNext: 3,
            spaceBetween: 26,
            slidesPerView: 6,
            loop: true,
            breakpoints: {
                300: {
                    slidesPerView: 1,
                    spaceBetween: 16
                },
                441: {
                    slidesPerView: 2,
                    spaceBetween: 16
                },
                769: {
                    slidesPerView: 3,
                    spaceBetween: 16
                },
                991: {
                    spaceBetween: 16,
                    slidesPerView: 4,
                },
                1200: {
                    spaceBetween: 26,
                    slidesPerView: 6,
                }
            }
        });
    }


    const sliderProduct = document.querySelectorAll('.js-slider-product');
    sliderProduct.forEach(el => {
        new Swiper(el, {
            lazyPreloadPrevNext: 2,
            spaceBetween: 26,
            slidesPerView: 4,
            navigation: {
                nextEl: '.swiper-button-next',
                prevEl: '.swiper-button-prev',
            },
            breakpoints: {
                300: {
                    slidesPerView: 'auto',
                    spaceBetween: 16

                },
                769: {
                    slidesPerView: 2,
                    spaceBetween: 16
                },
                991: {
                    spaceBetween: 16,
                    slidesPerView: 3,
                },
                1200: {
                    spaceBetween: 26,
                    slidesPerView: 4,
                }
            }
        });
    });


    if (document.getElementById('partnersSlider')) {
        if (widthScreen < 991) {
            new Swiper('#partnersSlider', {
                lazyPreloadPrevNext: 1,
                spaceBetween: 50,
                slidesPerView: 'auto',
                //loop: true,

            });
        }
    }

    //window.scrollTo(0, 0);


    const maskPhone = document.querySelectorAll('.js-mask-phone');

    maskPhone.forEach(el => {
        let im = new Inputmask("+7 999 999-99-99", {"clearIncomplete": true});
        im.mask(el);
    });

    if (document.getElementById('imgSlider')) {
        var swiper = new Swiper('#thumbnailSlider', {
            spaceBetween: 10,
            slidesPerView: 6,
            direction: 'vertical',
            watchSlidesProgress: true,
            navigation: {
                nextEl: '#thumbnailSliderDown',
                prevEl: '#thumbnailSliderUp',
            },
        });
        new Swiper('#imgSlider', {
            spaceBetween: 20,

            thumbs: {
                swiper: swiper,
            },
        });
    }



    if (document.getElementById('telModal')) {
        const validator = new window.JustValidate('#telModalForm');
        validator.addField('#telModalFIO', [
            {
                rule: 'required',
                errorMessage: 'Пожалуйста, введите ваше имя'
            }
        ]).addField('#telModalTel', [
            {
                rule: 'required',
                errorMessage: 'Пожалуйста, введите номер телефона'
            },
            {
                rule: 'customRegexp',
                value: /^[\d\+\-\(\)\s]{10,}$/,
                errorMessage: 'Введите корректный номер телефона'
            }
        ]).addField('#telModalPolitika', [
            {
                rule: 'required',
                errorMessage: 'Необходимо согласие с политикой конфиденциальности',
            }
        ], {
            errorsContainer: '#telModalPolitikaError',
        })

            .onSuccess((event) => {
                event.preventDefault();

                const formData = new FormData(event.target);

                const telModal = bootstrap.Modal.getInstance(document.getElementById('telModal'));
                if (telModal) {
                    telModal.hide();
                }

                const modal = new bootstrap.Modal(document.getElementById('successModal'));
                modal.show();

                event.target.reset();
            });
    }
    if (document.getElementById('orderModal')) {
        const validator = new window.JustValidate('#orderModalForm');
        validator.addField('#orderModalFIO', [
            {
                rule: 'required',
                errorMessage: 'Пожалуйста, введите ваше имя'
            }
        ]).addField('#orderModalTel', [
            {
                rule: 'required',
                errorMessage: 'Пожалуйста, введите номер телефона'
            },
            {
                rule: 'customRegexp',
                value: /^[\d\+\-\(\)\s]{10,}$/,
                errorMessage: 'Введите корректный номер телефона'
            }
        ]).addField('#orderModalPolitika', [
            {
                rule: 'required',
                errorMessage: 'Необходимо согласие с политикой конфиденциальности',
            }
        ], {
            errorsContainer: '#orderModalPolitikaError',
        })

            .onSuccess((event) => {
                event.preventDefault();

                const formData = new FormData(event.target);

                const telModal = bootstrap.Modal.getInstance(document.getElementById('orderModal'));
                if (telModal) {
                    telModal.hide();
                }

                const modal = new bootstrap.Modal(document.getElementById('successModal'));
                modal.show();

                event.target.reset();
            });
    }
    if (document.getElementById('consultationModal')) {
        const validator = new window.JustValidate('#consultationModalForm');
        validator.addField('#consultationModalFIO', [
            {
                rule: 'required',
                errorMessage: 'Пожалуйста, введите ваше имя'
            }
        ]).addField('#consultationModalTel', [
            {
                rule: 'required',
                errorMessage: 'Пожалуйста, введите номер телефона'
            },
            {
                rule: 'customRegexp',
                value: /^[\d\+\-\(\)\s]{10,}$/,
                errorMessage: 'Введите корректный номер телефона'
            }
        ]).addField('#consultationModalPolitika', [
            {
                rule: 'required',
                errorMessage: 'Необходимо согласие с политикой конфиденциальности',
            }
        ], {
            errorsContainer: '#consultationModalPolitikaError',
        })

            .onSuccess((event) => {
                event.preventDefault();

                const formData = new FormData(event.target);

                const telModal = bootstrap.Modal.getInstance(document.getElementById('consultationModal'));
                if (telModal) {
                    telModal.hide();
                }

                const modal = new bootstrap.Modal(document.getElementById('successModal'));
                modal.show();

                event.target.reset();
            });
    }

});
